"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[5293],{5301:e=>{e.exports=JSON.parse('{"tag":{"label":"sorting","permalink":"/leetcode/pt-BR/docs/tags/sorting","allTagsPath":"/leetcode/pt-BR/docs/tags","count":14,"items":[{"id":"problems/three-sum","title":"3Sum","description":"Given a list of integers, nums, return a list containing all triplets that sum to zero.","permalink":"/leetcode/pt-BR/docs/problems/three-sum"},{"id":"problems/assign-cake","title":"Assign Cake","description":"This question is asked by Amazon. You are at a birthday party and are asked to distribute cake to your guests. Each guest is only satisfied if the size of the piece of cake they\'re given matches their appetite (i.e., is greater than or equal to their appetite). Given two arrays, appetite and cake where the ith element of appetite represents the ith guest\'s appetite, and the elements of cake represents the sizes of cake you have to distribute, return the maximum number of guests that you can satisfy.","permalink":"/leetcode/pt-BR/docs/problems/assign-cake"},{"id":"problems/boats-to-save-people","title":"Boats to Save People","description":"This question is asked by Amazon. A ship is about to set sail and you are responsible for its safety precautions. More specifically, you are responsible for determining how many life rafts to carry onboard. You are given a list of all the passengers\' weights and are informed that a single life raft has a maximum capacity of limit and can hold at most two people. Return the minimum number of life rafts you must take onboard to ensure the safety of all your passengers.","permalink":"/leetcode/pt-BR/docs/problems/boats-to-save-people"},{"id":"problems/bricks-in-wheelbarrow","title":"Bricks in Wheelbarrow","description":"You are transporting bricks on a construction site and want to work as efficiently as possible. The weight of each brick is given by bricks[i]. Given a wheelbarrow that can carry up to (not including) 5000 pounds, return the maximum number of bricks you can place in your wheelbarrow to transport.","permalink":"/leetcode/pt-BR/docs/problems/bricks-in-wheelbarrow"},{"id":"problems/k-closest-points-to-origin","title":"K Closest Points to Origin","description":"Given a list of points, return the k closest points to the origin (0, 0).","permalink":"/leetcode/pt-BR/docs/problems/k-closest-points-to-origin"},{"id":"problems/kth-largest-element","title":"Kth Largest Element in an Array","description":"Given an array of integers, nums, and a value k, return the kth largest element.","permalink":"/leetcode/pt-BR/docs/problems/kth-largest-element"},{"id":"problems/labeled-items-max-sum","title":"Labeled Items Maximum Sum","description":"You are given a list of values and a list of labels. The ith element in labels represents the label of the ith element. Similarly, the ith element in values represents the value associated with the ith element (i.e. together, an \\"item\\" could be thought of as a label and a price).","permalink":"/leetcode/pt-BR/docs/problems/labeled-items-max-sum"},{"id":"problems/majority-element","title":"Majority Element","description":"High school students are voting for their class president and you\'re tasked with counting the votes. Each presidential candidate is represented by a unique integer and the candidate that should win the election is the candidate that has received more than half the votes. Given a list of integers, return the candidate that should become the class president.","permalink":"/leetcode/pt-BR/docs/problems/majority-element"},{"id":"problems/maximum-points-from-coins","title":"Maximum Points You Can Obtain","description":"This question is asked by Google. You are given a bag of coins, an initial energy of E, and want to maximize your number of points (which starts at zero). To gain a single point you can exchange coins[i] amount of energy (i.e. if I have 100 energy and a coin that has a value 50 I can exchange 50 energy to gain a point). If you do not have enough energy you can give away a point in exchange for an increase in energy by coins[i] amount (i.e. you give away a point and your energy is increased by the value of that coin: energy += coins[i]). Return the maximum number of points you can gain.","permalink":"/leetcode/pt-BR/docs/problems/maximum-points-from-coins"},{"id":"problems/merge-intervals","title":"Merge Intervals","description":"Given a list of interval objects, merge all overlapping intervals and return the result.","permalink":"/leetcode/pt-BR/docs/problems/merge-intervals"},{"id":"problems/reorganize-string","title":"Reorganize String","description":"This question is asked by Facebook. Given a string, check if it can be modified such that no two adjacent characters are the same. If it is possible, return any string that satisfies this condition and if it is not possible return an empty string.","permalink":"/leetcode/pt-BR/docs/problems/reorganize-string"},{"id":"problems/sort-array-by-parity-ii","title":"Sort Array By Parity II","description":"This question is asked by Amazon. Given an array of integers, nums, sort the array in any manner such that when i is even, nums[i] is even and when i is odd, nums[i] is odd.","permalink":"/leetcode/pt-BR/docs/problems/sort-array-by-parity-ii"},{"id":"problems/third-maximum-number","title":"Third Maximum Number","description":"Given an array nums, return the third largest (distinct) value.","permalink":"/leetcode/pt-BR/docs/problems/third-maximum-number"},{"id":"problems/top-k-frequent-words","title":"Top K Frequent Words","description":"Given a list of words, return the top k frequently occurring words.","permalink":"/leetcode/pt-BR/docs/problems/top-k-frequent-words"}],"unlisted":false}}')}}]);